result = js('''
(function() {
  // Try to find the main TradingView chart iframe or web component
  const iframes = document.querySelectorAll(\"iframe\");
  for (let i of iframes) {
    if (i.src.includes(\"tradingview\")) {
      return \"found TV iframe: \" + i.src;
    }
  }
  // Try shadow DOM
  const tvWidget = document.querySelector(\"[class*=\'chart-container\']\") || 
                   document.querySelector(\"tradingview-widget\") ||
                   document.querySelector(\"[id*=\'widget\']\");
  if (tvWidget) {
    return \"widget: \" + tvWidget.tagName + \" class: \" + tvWidget.className;
  }
  return \"no TV elements found. page: \" + document.title;
})()
''')
print(result)
